import{_ as i,c as l,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const u=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/gh-aw-开发工具.md","filePath":"github汇总/开发工具/gh-aw-开发工具.md"}'),t={name:"github汇总/开发工具/gh-aw-开发工具.md"};function h(n,a,o,s,d,c){return e(),l("div",null,a[0]||(a[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>GitHub Agentic Workflows (gh-aw)</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>GitHub</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>传统CI/CD脚本编写复杂，需要专业知识，难以维护和理解。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><p>用自然语言markdown编写代理工作流，并在GitHub Actions中运行，实现仓库任务自动化。</p><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>支持自然语言编写工作流</li><li>多层安全防护机制</li><li>与GitHub Actions无缝集成</li><li>提供多种工作流类型</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/github/gh-aw" target="_blank" rel="noreferrer">https://github.com/github/gh-aw</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于需要在GitHub仓库中自动化任务的开发者和团队。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>拥有GitHub账号</li><li>仓库已启用GitHub Actions</li><li>了解基本的markdown语法</li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><ol><li><p><strong>安装扩展</strong></p><ul><li>目标：安装GitHub Agentic Workflows扩展</li><li>位置：GitHub仓库</li><li>命令：按照Quick Start Guide中的步骤操作</li><li>成功标志：扩展安装完成</li><li>失败处理：参考官方文档中的故障排除部分</li></ul></li><li><p><strong>添加工作流</strong></p><ul><li>目标：在仓库中添加代理工作流</li><li>位置：仓库根目录</li><li>命令：创建markdown格式的工作流文件</li><li>成功标志：工作流文件创建成功</li><li>失败处理：检查markdown语法是否正确</li></ul></li><li><p><strong>运行工作流</strong></p><ul><li>目标：在GitHub Actions中运行工作流</li><li>位置：GitHub Actions界面</li><li>命令：触发工作流运行</li><li>成功标志：工作流执行完成</li><li>失败处理：查看日志排查错误</li></ul></li></ol><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li>访问地址：GitHub仓库的Actions标签页</li><li>检查命令：查看工作流执行状态</li><li>预期返回：工作流执行成功，任务完成</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>权限错误</strong></p><ul><li>现象：工作流无法执行写操作</li><li>可能原因：未配置安全输出</li><li>解决步骤：按照文档配置安全输出机制</li></ul></li><li><p><strong>语法错误</strong></p><ul><li>现象：工作流解析失败</li><li>可能原因：markdown语法错误</li><li>解决步骤：检查并修正markdown文件</li></ul></li><li><p><strong>网络隔离问题</strong></p><ul><li>现象：工作流无法访问外部资源</li><li>可能原因：网络隔离限制</li><li>解决步骤：配置Agent Workflow Firewall</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><ul><li>使用MCP Gateway统一管理模型上下文协议调用</li><li>利用gh-aw-actions共享库提供额外功能</li></ul><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README/仓库信息中未提供完整教程，具体安装步骤请参考官方文档。</p>',31)]))}const p=i(t,[["render",h]]);export{u as __pageData,p as default};
